import fs from 'node:fs';
import path from 'node:path';
import { expect, test } from '@playwright/test';

const SIDE_PANEL_JS = fs.readFileSync(
  path.resolve(__dirname, '../../chrome-extension/dist/sidepanel.js'),
  'utf8',
);
const BACKGROUND_JS = fs.readFileSync(
  path.resolve(__dirname, '../../chrome-extension/dist/background.js'),
  'utf8',
);

test.describe('Extension Unit Tests', () => {
  test.describe('Side Panel Logic', () => {
    test('should update UI when receiving a newPayload message', async ({
      page,
    }) => {
      // 1. Setup mock chrome environment and load sidepanel.js
      await page.setContent(`
        <div id="status-dot"></div>
        <div id="status-text"></div>
        <div id="prompt-display"></div>
        <button id="copy-prompt-btn"></button>
        <button id="copy-project-path-btn"></button>
        <button id="copy-context-btn"></button>
        <textarea id="web-response"></textarea>
        <button id="submit-response-btn"></button>
        <input id="token-input" type="password">
        <button id="save-token-btn"></button>
      `);

      await page.evaluate((script) => {
        // Mock chrome API
        // biome-ignore lint/suspicious/noExplicitAny: mocking global chrome
        (window as any).chrome = {
          storage: {
            local: {
              get: (_keys, cb) => cb({}),
              set: (_data, cb) => cb?.(),
            },
          },
          runtime: {
            onMessage: {
              addListener: (listener) => {
                // biome-ignore lint/suspicious/noExplicitAny: mocking listener
                (window as any).messageListener = listener;
              },
            },
            sendMessage: () => {},
          },
        };

        // Execute sidepanel.js logic
        const scriptEl = document.createElement('script');
        scriptEl.textContent = script;
        document.body.appendChild(scriptEl);
      }, SIDE_PANEL_JS);

      // 2. Simulate newPayload message
      const mockPayload = {
        prompt: 'Test Prompt',
        projectPath: '/test/path',
        zipData: 'mock-zip',
      };

      await page.evaluate((payload) => {
        // biome-ignore lint/suspicious/noExplicitAny: triggering mock listener
        (window as any).messageListener({ type: 'newPayload', data: payload });
      }, mockPayload);

      // 3. Assertions
      const promptText = await page.$eval(
        '#prompt-display',
        (el) => el.textContent,
      );
      expect(promptText).toBe('Test Prompt');

      const isPromptEnabled = await page.$eval(
        '#copy-prompt-btn',
        (el) => !el.disabled,
      );
      expect(isPromptEnabled).toBe(true);
    });
  });

  test.describe('Background Logic', () => {
    test('should attempt connection when token is available', async ({
      page,
    }) => {
      const mockToken = 'test-token';

      const logs = await page.evaluate(
        // biome-ignore lint/suspicious/useAwait: evaluating in browser
        async ({ script, token }) => {
          const logs: string[] = [];
          const _originalConsoleLog = console.log;
          console.log = (...args) => logs.push(args.join(' '));

          // Mock chrome API
          // biome-ignore lint/suspicious/noExplicitAny: mocking global chrome
          (window as any).chrome = {
            storage: {
              local: {
                get: (_keys, cb) => cb({ token }),
                set: () => {},
                onChanged: { addListener: () => {} },
              },
            },
            runtime: {
              onMessage: { addListener: () => {} },
              onInstalled: { addListener: () => {} },
              sendMessage: () => {},
            },
            sidePanel: { setPanelBehavior: () => Promise.resolve() },
          };

          // Mock WebSocket
          // biome-ignore lint/suspicious/noExplicitAny: mocking global WebSocket
          (window as any).WebSocket = class {
            constructor(url) {
              logs.push(`WebSocket connecting to: ${url}`);
            }
          };

          // Execute background.js
          const scriptEl = document.createElement('script');
          scriptEl.textContent = script;
          document.body.appendChild(scriptEl);

          return logs;
        },
        { script: BACKGROUND_JS, token: mockToken },
      );

      expect(logs.some((l) => l.includes(`token=${mockToken}`))).toBe(true);
    });
  });
});

import { EventEmitter } from 'node:events';
import { expect, test } from '@playwright/test';
import sinon from 'sinon';
import {
  type ClientDependencies,
  ensureDaemonRunning,
  sendPayloadToDaemon,
  waitForResult,
} from '../../mcp-server/src/client';

test.describe('mcp-client unit tests', () => {
  let deps: ClientDependencies;
  // biome-ignore lint/suspicious/noExplicitAny: mocking WebSocket
  let mockWs: any;

  test.beforeEach(() => {
    mockWs = new EventEmitter();
    mockWs.send = sinon.stub();
    mockWs.close = sinon.stub();

    deps = {
      // biome-ignore lint/suspicious/noExplicitAny: mocking constructor
      WebSocket: sinon.stub().returns(mockWs) as any,
      // biome-ignore lint/suspicious/noExplicitAny: mocking child process
      spawn: sinon.stub().returns({ unref: sinon.stub() }) as any,
      readFileSync: sinon.stub().returns('mock-token'),
    };
  });

  test.describe('ensureDaemonRunning', () => {
    test('should resolve token if daemon is already running', async () => {
      const promise = ensureDaemonRunning(deps);

      // Simulate connection success
      mockWs.emit('open');

      const token = await promise;
      expect(token).toBe('mock-token');
      expect(mockWs.close.calledOnce).toBe(true);
    });

    test('should spawn daemon if connection is refused', async () => {
      const promise = ensureDaemonRunning(deps);

      // Simulate connection failure
      mockWs.emit('error', { code: 'ECONNREFUSED' });

      const token = await promise;

      expect(token).toBe('mock-token');
      const spawnStub = deps.spawn as sinon.SinonStub;
      expect(spawnStub.calledOnce).toBe(true);
      expect(spawnStub.getCall(0).args[2].stdio).not.toEqual('ignore');
    });
  });

  test.describe('sendPayloadToDaemon', () => {
    test('should send payload and resolve immediately', async () => {
      const payload = {
        handoff_id: 'id',
        prompt: 'test',
        projectPath: '/path',
      };
      const promise = sendPayloadToDaemon(payload, deps);

      mockWs.emit('open');

      await promise;

      expect(mockWs.send.calledOnce).toBe(true);
      const sentData = JSON.parse(mockWs.send.getCall(0).args[0]);
      expect(sentData).toEqual({ type: 'payload', data: payload });
      expect(mockWs.close.calledOnce).toBe(true);
    });
  });

  test.describe('waitForResult', () => {
    test('should resolve with response data when received', async () => {
      const promise = waitForResult('my-id', deps);

      mockWs.emit('open');

      // Simulate daemon sending back the response
      mockWs.emit(
        'message',
        JSON.stringify({
          type: 'response',
          handoff_id: 'my-id',
          data: 'research results',
        }),
      );

      const result = await promise;

      expect(result).toBe('research results');
      expect(mockWs.close.calledOnce).toBe(true);
    });

    test('should reject if timeout occurs', async () => {
      // Pass a very short timeout
      const promise = waitForResult('my-id', deps, 10);

      mockWs.emit('open');

      await expect(promise).rejects.toThrow(
        'Timeout waiting for research response from browser.',
      );
    });
  });
});

import * as cp from 'node:child_process';
import * as fs from 'node:fs';
import * as os from 'node:os';
import * as path from 'node:path';
import { WebSocket } from 'ws';

const PORT = 8080;
const TOKEN_FILE_PATH = path.join(os.homedir(), '.gemini', 'web-handoff-token');

export interface ClientDependencies {
  WebSocket: typeof WebSocket;
  spawn: typeof cp.spawn;
  readFileSync: typeof fs.readFileSync;
}

const defaultDeps: ClientDependencies = {
  WebSocket,
  spawn: cp.spawn,
  readFileSync: fs.readFileSync,
};

export function ensureDaemonRunning(
  deps: ClientDependencies = defaultDeps,
): Promise<string> {
  return new Promise((resolve, reject) => {
    // Try to connect to see if it's already running
    const ws = new deps.WebSocket(`ws://127.0.0.1:${PORT}/mcp`);

    ws.on('open', () => {
      // Daemon is running. Read the token file.
      ws.close();
      resolveToken();
    });

    ws.on('error', (err: { code?: string }) => {
      if (err.code === 'ECONNREFUSED') {
        // Not running, spawn it
        startDaemon();
      } else {
        reject(err);
      }
    });

    function resolveToken() {
      try {
        const token = deps.readFileSync(TOKEN_FILE_PATH, 'utf-8');
        resolve(token);
      } catch (_e) {
        reject(
          new Error('Daemon is running but token file could not be read.'),
        );
      }
    }

    function startDaemon() {
      const daemonPath = path.join(__dirname, 'daemon.js');
      const logPath = path.join(
        os.homedir(),
        '.gemini',
        'web-handoff-daemon.log',
      );
      const out = fs.openSync(logPath, 'a');
      const err = fs.openSync(logPath, 'a');

      const child = deps.spawn(process.execPath, [daemonPath], {
        detached: true,
        stdio: ['ignore', out, err],
      });
      child.unref();

      // Wait a moment for it to start and write the token file
      setTimeout(() => {
        resolveToken();
      }, 500);
    }
  });
}

export interface DaemonPayload {
  handoff_id: string;
  prompt: string;
  projectPath: string;
  zipData?: string; // base64 encoded
}

/**
 * Sends the payload to the daemon without blocking for the research result.
 */
export function sendPayloadToDaemon(
  payload: DaemonPayload,
  deps: ClientDependencies = defaultDeps,
): Promise<void> {
  return new Promise((resolve, reject) => {
    const ws = new deps.WebSocket(`ws://127.0.0.1:${PORT}/mcp`);

    ws.on('open', () => {
      ws.send(JSON.stringify({ type: 'payload', data: payload }));
      ws.close();
      resolve();
    });

    ws.on('error', (err) => {
      reject(err);
    });
  });
}

/**
 * Blocks and waits for the research result associated with a handoff_id.
 */
export function waitForResult(
  handoff_id: string,
  deps: ClientDependencies = defaultDeps,
  timeoutMs: number = 30 * 60 * 1000, // Default 30 minutes
): Promise<string> {
  return new Promise((resolve, reject) => {
    console.log(`Client: Connecting to daemon to wait for ${handoff_id}...`);
    const ws = new deps.WebSocket(`ws://127.0.0.1:${PORT}/mcp`);

    let timeout: NodeJS.Timeout;

    ws.on('open', () => {
      console.log(
        `Client: Connected to daemon, subscribing to ${handoff_id}...`,
      );
      // Send a request to the daemon to wait for this ID
      ws.send(JSON.stringify({ type: 'subscribe', handoff_id }));

      timeout = setTimeout(() => {
        ws.close();
        reject(
          new Error('Timeout waiting for research response from browser.'),
        );
      }, timeoutMs);
    });

    ws.on('message', (data) => {
      console.log(
        `Client: Message received from daemon: ${data.toString().slice(0, 100)}...`,
      );
      try {
        const message = JSON.parse(data.toString());
        if (message.type === 'response' && message.handoff_id === handoff_id) {
          console.log(
            `Client: Matching response found for ${handoff_id}, resolving.`,
          );
          clearTimeout(timeout);
          ws.close();
          resolve(message.data);
        }
      } catch (_e) {
        // ignore invalid json
      }
    });

    ws.on('error', (err) => {
      console.error(`Client: WebSocket error:`, err);
      clearTimeout(timeout);
      reject(err);
    });

    ws.on('close', () => {
      console.log(`Client: WebSocket closed.`);
      clearTimeout(timeout);
    });
  });
}

import { expect, test } from '@playwright/test';
import sinon from 'sinon';
import {
  delegateWebResearchSchema,
  handleDelegateWebResearch,
  handleGetResearchResult,
  type ToolDependencies,
} from '../../mcp-server/src/tools';

test.describe('mcp-tools unit tests', () => {
  let deps: ToolDependencies;
  // biome-ignore lint/suspicious/noExplicitAny: mocking Zip
  let mockZip: any;

  test.beforeEach(() => {
    mockZip = {
      addFile: sinon.stub(),
      toBuffer: sinon.stub().returns(Buffer.from('mock-zip-buffer')),
    };

    deps = {
      ensureDaemonRunning: sinon.stub().resolves('mock-token'),
      sendPayloadToDaemon: sinon.stub().resolves(),
      waitForResult: sinon.stub().resolves('final research data'),
      existsSync: sinon.stub().returns(true),
      readFileSync: sinon.stub().returns(Buffer.from('file content')),
      // biome-ignore lint/suspicious/noExplicitAny: mocking constructor
      Zip: sinon.stub().returns(mockZip) as any,
    };
  });

  test('should validate the input schema', () => {
    const result = delegateWebResearchSchema.safeParse({ prompt: 'test' });
    expect(result.success).toBe(true);
  });

  test('should fail validation if more than 10 context_files are provided', () => {
    const result = delegateWebResearchSchema.safeParse({
      prompt: 'test',
      context_files: Array.from({ length: 11 }, (_, i) => `file${i}.txt`),
    });
    expect(result.success).toBe(false);
  });

  test('should return a success message with handoff_id when handled', async () => {
    const response = await handleDelegateWebResearch({ prompt: 'test' }, deps);

    expect(response.content[0].text).toContain(
      'Research task delegated to browser with ID',
    );
    expect(response.content[0].text).toContain('get_research_result');
    expect(response.isError).toBeFalsy();
    expect((deps.sendPayloadToDaemon as sinon.SinonStub).calledOnce).toBe(true);
  });

  test('should return the research result from get_research_result', async () => {
    (deps.waitForResult as sinon.SinonStub).resolves('final research data');

    const response = await handleGetResearchResult(
      { handoff_id: 'mock-id' },
      deps,
    );

    expect(response.content[0].text).toBe('final research data');
    expect(response.isError).toBeFalsy();
    expect((deps.waitForResult as sinon.SinonStub).calledWith('mock-id')).toBe(
      true,
    );
  });

  test('should read files and create a zip buffer when context_files are provided', async () => {
    const _response = await handleDelegateWebResearch(
      {
        prompt: 'test',
        context_files: ['file1.txt', 'file2.txt'],
      },
      deps,
    );

    // biome-ignore lint/suspicious/noExplicitAny: mocking Zip
    expect(deps.Zip as any).toHaveBeenCalled;
    expect(mockZip.addFile.calledTwice).toBe(true);
    expect(mockZip.toBuffer.calledOnce).toBe(true);

    const sentPayload = (deps.sendPayloadToDaemon as sinon.SinonStub).getCall(0)
      .args[0];
    expect(sentPayload.zipData).toBe(
      Buffer.from('mock-zip-buffer').toString('base64'),
    );
    expect(sentPayload.handoff_id).toBeTruthy();
  });

  test('should ignore missing files when creating a zip buffer', async () => {
    (deps.existsSync as sinon.SinonStub).callsFake(
      (path) => path === 'file1.txt',
    );

    await handleDelegateWebResearch(
      {
        prompt: 'test',
        context_files: ['file1.txt', 'missing.txt'],
      },
      deps,
    );

    expect(mockZip.addFile.calledOnce).toBe(true);
  });
});

import * as crypto from 'node:crypto';
import fs from 'node:fs';
import path from 'node:path';
import AdmZip from 'adm-zip';
import { z } from 'zod';
import * as client from './client';

export const delegateWebResearchSchema = z.object({
  prompt: z
    .string()
    .describe(
      "The comprehensive research prompt or task to delegate to the Gemini web interface. Use this when the task requires advanced reasoning, extensive web browsing, multi-modal analysis, or features like 'Projects' and 'Gems' that are better handled in the browser.",
    ),
  context_files: z
    .array(z.string())
    .max(10, 'Array must contain at most 10 element(s)')
    .optional()
    .describe(
      "An optional array of up to 10 specific local file paths to provide as a Context ZIP for targeted analysis. For entire codebase uploads, the user will be prompted to use the 'Copy Project Path' button in the side panel.",
    ),
});

export const getResearchResultSchema = z.object({
  handoff_id: z
    .string()
    .describe('The unique ID of the research task to retrieve results for.'),
});

export interface ToolDependencies {
  ensureDaemonRunning: typeof client.ensureDaemonRunning;
  sendPayloadToDaemon: typeof client.sendPayloadToDaemon;
  waitForResult: typeof client.waitForResult;
  existsSync: typeof fs.existsSync;
  readFileSync: typeof fs.readFileSync;
  Zip: typeof AdmZip;
}

const defaultDeps: ToolDependencies = {
  ensureDaemonRunning: client.ensureDaemonRunning,
  sendPayloadToDaemon: client.sendPayloadToDaemon,
  waitForResult: client.waitForResult,
  existsSync: fs.existsSync,
  readFileSync: fs.readFileSync,
  Zip: AdmZip,
};

export async function handleDelegateWebResearch(
  args: z.infer<typeof delegateWebResearchSchema>,
  deps: ToolDependencies = defaultDeps,
) {
  try {
    // Ensure daemon is running
    const token = await deps.ensureDaemonRunning();

    let zipBuffer: Buffer | undefined;

    if (args.context_files && args.context_files.length > 0) {
      const zip = new deps.Zip();
      for (const filePath of args.context_files) {
        if (deps.existsSync(filePath)) {
          const fileContent = deps.readFileSync(filePath);
          zip.addFile(path.basename(filePath), fileContent);
        } else {
          console.warn(`File not found: ${filePath}, skipping...`);
        }
      }
      zipBuffer = zip.toBuffer();
    }

    const handoff_id = crypto.randomUUID();
    // The current working directory is considered the project root in this context.
    const projectPath = process.cwd();

    await deps.sendPayloadToDaemon({
      handoff_id,
      prompt: args.prompt,
      projectPath: projectPath,
      zipData: zipBuffer ? zipBuffer.toString('base64') : undefined,
    });

    return {
      content: [
        {
          type: 'text' as const,
          text:
            `Research task delegated to browser with ID: ${handoff_id}.\n\n` +
            `1. Connect your Chrome Extension to: ws://127.0.0.1:8080/ext?token=${token}\n` +
            `2. Perform the research in your browser.\n` +
            `3. Submit the result back via the Side Panel.\n\n` +
            `**CRITICAL:** You must now call 'get_research_result' with handoff_id: "${handoff_id}" to await and receive the final research data.`,
        },
      ],
    };
  } catch (error: unknown) {
    return {
      content: [
        {
          type: 'text' as const,
          text: `Failed to delegate web research: ${error instanceof Error ? error.message : String(error)}`,
        },
      ],
      isError: true,
    };
  }
}

export async function handleGetResearchResult(
  args: z.infer<typeof getResearchResultSchema>,
  deps: ToolDependencies = defaultDeps,
) {
  try {
    await deps.ensureDaemonRunning();

    const result = await deps.waitForResult(args.handoff_id);

    return {
      content: [
        {
          type: 'text' as const,
          text: result,
        },
      ],
    };
  } catch (error: unknown) {
    return {
      content: [
        {
          type: 'text' as const,
          text: `Failed to get research result: ${error instanceof Error ? error.message : String(error)}`,
        },
      ],
      isError: true,
    };
  }
}
